import React from "react";
import { Settings as SettingsIcon } from "lucide-react";

export function SettingsPage() {
  return (
    <div className="space-y-6 animate-in fade-in duration-500">

      {/* Cabecera */}
      <div>
        <h1 className="text-3xl font-bold text-white tracking-tight">Ajustes</h1>
        <p className="text-gray-400 mt-1">Preferencias del sistema y gestión del centro.</p>
      </div>

      {/* Contenedor Vacío / Placeholder */}
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-2xl p-20 flex flex-col items-center text-center shadow-xl">
        <div className="w-24 h-24 bg-[#E31C25]/5 rounded-full flex items-center justify-center mb-6 border border-[#E31C25]/10">
          <SettingsIcon className="w-12 h-12 text-[#E31C25] opacity-80" />
        </div>
        <h2 className="text-2xl font-bold text-white mb-2">Preferencias del Sistema</h2>
        <p className="text-gray-400 max-w-sm mx-auto">
          Configura las opciones de la aplicación, permisos del personal y ajustes de facturación de tu gimnasio.
        </p>
      </div>

    </div>
  );
}
